const isAssignee = (t,name) => !!name && taskAssignees(t).includes(name)
// "En mi lista": soy responsable o me delegaron la tarea (los delegados también la ven).
const enMiLista = (t,name) => isAssignee(t,name) || (!!name && ((t&&t.delegated_to)||[]).includes(name))
const ADMIN_NAMES = ['Cristóbal','Erasmo']

// Saldo disponible de caja chica del usuario = fondos entregados − TODOS sus gastos (liquidados o no).
// Liquidar es neutro para el saldo: el gasto ya descontó la plata; solo un fondo nuevo lo sube.
// Queda en $0 si fondos=gastos, o en el remanente si hubo diferencia. NO excluir los liquidados:
// si se excluyen, el saldo sube artificialmente al liquidar (los fondos seguirían sumando completos).
// Fuente única: la usan CajaChicaView ("Mi caja"), el panel Gestión del Dashboard y el KPI de Tareas.
// Excluye los gastos con paid_by_client=true (los pagó el cliente directo: se rinden pero no salen de la caja chica del usuario).
const saldoCajaChica = (pettyCash, expenses, userName) => {
  if(!userName) return 0
  const entregado = (pettyCash||[]).filter(p=>p.user_name===userName).reduce((a,p)=>a+(p.amount||0),0)
  const gastado = (expenses||[]).filter(e=>e.type==='gasto'&&e.created_by===userName&&!e.paid_by_client).reduce((a,e)=>a+(e.amount||0),0)
  return entregado - gastado
}

// Fuente única para "fondos − gastos" de un cliente. Siempre con guarda ||0 (nunca NaN).
function fgCliente(expenses, clientId){
  let fondos=0, gastos=0
  ;(expenses||[]).forEach(e=>{ if(e.client_id!==clientId) return; if(e.type==='fondo') fondos+=(e.amount||0); else if(!e.no_descuenta_saldo) gastos+=(e.amount||0) })
  return {fondos, gastos, saldo:fondos-gastos}
}
const saldoCliente = (expenses, clientId) => fgCliente(expenses, clientId).saldo

// FUENTE ÚNICA del saldo de un fondo de cliente para RENDICIONES (modal, PDF y correo usan ESTA).
// saldo disponible = fondos recibidos − gastos YA RENDIDOS (de todas las rendiciones de la RS).
// Los gastos no rendidos no descuentan saldo todavía. scopeEntId acota a una razón social (multi-RS); null = todo el cliente.
function rendicionSaldo(expenses, clientId, scopeEntId){
  const movs=(expenses||[]).filter(e=>e.client_id===clientId && (!scopeEntId || e.entity_id===scopeEntId))
  const totFondos=movs.filter(e=>e.type==='fondo').reduce((a,e)=>a+(e.amount||0),0)
  const rendido=movs.filter(e=>e.type==='gasto'&&e.client_rendered_at).reduce((a,e)=>a+(e.amount||0),0)
  return {totFondos, rendido, saldo:totFondos-rendido}
}
// Rendiciones ANTERIORES (para el desglose "Resumen del fondo"): agrupa gastos ya rendidos por rendición,
// excluyendo la actual. Recibe movimientos ya acotados a la RS. Devuelve [{total,fecha}] y la suma.
function rendicionesPreviasDe(scopedMovs, excludeRenderId){
  const grupos={}
  ;(scopedMovs||[]).forEach(e=>{ if(e.type==='gasto'&&e.client_rendered_at&&e.client_render_id&&e.client_render_id!==excludeRenderId){ const g=grupos[e.client_render_id]||(grupos[e.client_render_id]={total:0,fecha:e.client_rendered_at}); g.total+=(e.amount||0); if((e.client_rendered_at||'')<(g.fecha||'')) g.fecha=e.client_rendered_at } })
  const previas=Object.values(grupos).sort((a,b)=>(a.fecha||'')>(b.fecha||'')?1:-1)
  return {previas, rendidoAntes:previas.reduce((a,g)=>a+g.total,0)}
}
// Al anular una rendición, su cobro de reembolso queda huérfano (sigue cobrable). Lo anula (reversible, no lo borra).
// Devuelve los reembolsos anulados para refrescar estado local y avisar.
async function anularReembolsoDeRendicion(r, billing){
  const reembolsos=(billing||[]).filter(b=>b.billing_type==='reembolso'&&b.status!=='Anulada'&&(b.notes||'').includes(`Rendición ID ${r.id}`))
  if(reembolsos.length){ const {error}=await supabase.from('billing').update({status:'Anulada'}).in('id',reembolsos.map(b=>b.id)); if(error) throw error }
  return reembolsos
}

// Saldos por razón social (entity) de un cliente. Con 1 RS, todo (incl. sin entity_id) va a esa RS.
// Con 2+ RS, los movimientos sin entity_id quedan en un grupo "Sin razón social". total = suma de todo.
function rsBalances(clientId, expenses, entities){
  const ents = entities||[]
  const single = ents.length===1
  const buckets = ents.map(e=>({entity:e,fondos:0,gastos:0}))
  const byId={}; buckets.forEach(b=>byId[b.entity.id]=b)
  const sinRS={entity:null,fondos:0,gastos:0,n:0}
  ;(expenses||[]).filter(e=>e.client_id===clientId).forEach(e=>{
    let b
    if(e.entity_id&&byId[e.entity_id]) b=byId[e.entity_id]
    else if(single&&buckets.length) b=buckets[0]
    else { b=sinRS; sinRS.n++ }
    if(e.type==='fondo') b.fondos+=(e.amount||0); else if(!e.no_descuenta_saldo) b.gastos+=(e.amount||0)
  })
  const ws = b=>({...b,saldo:b.fondos-b.gastos})
  const porRS = buckets.map(ws)
  const sin = sinRS.n>0 ? ws(sinRS) : null
  const all = porRS.concat(sin?[sin]:[])
  const tot = all.reduce((a,b)=>({fondos:a.fondos+b.fondos,gastos:a.gastos+b.gastos}),{fondos:0,gastos:0})
  return {porRS, sin, total:{...tot,saldo:tot.fondos-tot.gastos}}
}

// FUENTE ÚNICA del documento de rendición (HTML imprimible). La usan el historial ("Ver PDF")
// y RendicionModal (al enviar), para que ambos PDFs sean idénticos. Recibe datos ya normalizados.
// gastos: [{date,concept,category,amount}] · fondos: [{date,concept,amount}]
function rendicionDocHtml({ razon, rut, periodo, fechaEmision, dirigidoA, gastos, fondos, totGastos, totFondos, rendidoAntes=0, rendicionesPrevias=[], correlativo=null, project=null, subproject=null, lang='es' }){
  const A='#003C50', GRAY='#E4E8EB', MUTED='#537281', AZUL3='#99ABB4', TXT='#3D3D3D'
  const EN = lang==='en'
  const T = EN ? {title:'Expense Report',outstanding:'Outstanding balance — transfer to Liberona Escala',company:'Company',rut:'Tax ID (RUT)',bank:'Bank',account:'Checking account',confEmail:'Confirmation email',fundSummary:'Fund summary',reportPrev:'Report',previous:'previous',fundsReceived:'Funds received',thisReport:'This report',availBalance:'Available balance',expPeriod:'Expenses (period)',balFavor:'Balance in your favor',balPending:'Outstanding balance',project:'Project',reportNo:'Report No.',period:'Period',issued:'Issued',attn:'Attn',date:'Date',concept:'Description',category:'Category',amount:'Amount',totalExp:'Total expenses',noFunds:'No funds recorded',fundsSection:'Funds received',footerDoc:'Expense report',printBtn:'Print / Save PDF',receiptBadge:'✓ receipt',fundDefault:'Funds received',expW:n=>`${n} expense${n!==1?'s':''}`,withReceipt:(a,b)=>`${a} of ${b} with supporting receipts (available upon request).`}
    : {title:'Rendición de gastos',outstanding:'Saldo pendiente — transferir a Liberona Escala',company:'Razón social',rut:'RUT',bank:'Banco',account:'N° cuenta corriente',confEmail:'Email confirmación',fundSummary:'Resumen del fondo',reportPrev:'Rendición',previous:'anterior',fundsReceived:'Fondos recibidos',thisReport:'Esta rendición',availBalance:'Saldo disponible',expPeriod:'Gastos del período',balFavor:'Saldo a favor',balPending:'Saldo pendiente',project:'Proyecto',reportNo:'Rendición N°',period:'Período',issued:'Emisión',attn:'Dirigido a',date:'Fecha',concept:'Concepto',category:'Categoría',amount:'Monto',totalExp:'Total gastos',noFunds:'Sin fondos registrados',fundsSection:'Fondos recibidos',footerDoc:'Rendición de gastos',printBtn:'Imprimir / Guardar PDF',receiptBadge:'✓ respaldo',fundDefault:'Fondo recibido',expW:n=>`${n} gasto${n!==1?'s':''}`,withReceipt:(a,b)=>`${a} de ${b} con comprobante de respaldo (disponibles a solicitud).`}
  // Saldo disponible = fondos recibidos − rendido en tandas anteriores − esta rendición.
  const saldo = totFondos - rendidoAntes - totGastos
  const badge = (cat)=>{ const c=(cat||'').toLowerCase(); let bg='#E4E8EB',fg=MUTED; if(c.includes('notar')){bg='#E6F1FB';fg=A} else if(c.includes('transp')){bg='#E1F5EE';fg=C.greenText} return `<span style='display:inline-block;padding:2px 8px;border-radius:4px;font-size:9px;font-weight:600;background:${bg};color:${fg}'>${RENDCAT(cat)}</span>` }
  const filasGastos = gastos.map(e=>`<tr><td style='white-space:nowrap'>${fmtFechaDMY(e.date)}</td><td>${e.concept||'—'}${e.ot_number?` <span style='font-size:8px;font-weight:700;color:#185FA5;white-space:nowrap'>${String(e.ot_number).toUpperCase().startsWith('OT')?e.ot_number:'OT-'+e.ot_number}</span>`:''}${e.respaldo?` <span style='font-size:8px;font-weight:700;color:#0F6E56;background:#E1F5EE;padding:1px 5px;border-radius:4px;white-space:nowrap'>${T.receiptBadge}</span>`:''}</td><td>${badge(e.category)}</td><td style='text-align:right;font-weight:600;white-space:nowrap'>${fmtN(e.amount)}</td></tr>`).join('')
  const conRespaldoN = gastos.filter(e=>e.respaldo).length
  const filasFondos = fondos.length ? fondos.map(e=>`<tr><td style='width:90px;white-space:nowrap'>${fmtFechaDMY(e.date)}</td><td>${e.concept||T.fundDefault}</td><td style='text-align:right;font-weight:600;color:#0F6E56'>${fmtN(e.amount)}</td></tr>`).join('') : `<tr><td colspan='3' style='color:${MUTED};text-align:center;padding:10px'>${T.noFunds}</td></tr>`
  let saldoBox=''
  // Solo para saldo EN CONTRA: datos de la cuenta de LEA (útil tenerlos en el documento). La ACCIÓN (devolver / queda
  // para próximos trabajos / transferir) la define el CORREO según el estado del cliente — el PDF no la repite para no contradecir.
  if(saldo<0){ const row=(l,v)=>`<div style='display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #F1D4D4;font-size:10px'><span style='color:${MUTED}'>${l}</span><span style='font-weight:600;color:${TXT}'>${v}</span></div>`; saldoBox=`<div class='saldo-box' style='border:1px solid #F7C1C1;background:#FCEBEB;border-radius:8px;padding:14px 18px;margin-top:18px'><div style='font-size:11px;font-weight:700;color:${TXT};margin-bottom:10px'>${T.outstanding}</div>${row(T.company,'Liberona Escala Abogados Limitada')}${row(T.rut,'77.700.387-9')}${row(T.bank,'Banco BICE')}${row(T.account,'138392-2')}${row(T.confEmail,'administracion@leabogados.cl')}</div>` }
  const sep='border-left:1px solid #B9C2C8;margin-left:12px;padding-left:12px'
  // Recuadro "Resumen del fondo": ledger auditable — fondos − (rendiciones previas) − esta rendición = saldo.
  const lrow=(l,v,neg)=>`<div style='display:flex;justify-content:space-between;align-items:baseline;padding:4px 0'><span style='font-size:10px;color:${AZUL3}'>${l}</span><span style='font-size:12px;font-weight:600;color:#fff;white-space:nowrap'>${neg?'−':''}${v}</span></div>`
  const filasPrevias = (rendicionesPrevias||[]).map(p=>lrow(`${T.reportPrev} ${p.fecha?fmtFechaDMY(String(p.fecha).slice(0,10)):T.previous}`, fmtN(p.total), true)).join('')
  const resumenBox=`<div style='background:${A};border-radius:8px;padding:14px 18px;margin-top:18px;color:#fff'><div style='font-size:9px;text-transform:uppercase;letter-spacing:.5px;color:${AZUL3};margin-bottom:8px'>${T.fundSummary}${razon?` · ${razon}`:''}</div>${lrow(T.fundsReceived, fmtN(totFondos))}${filasPrevias}${lrow(T.thisReport, fmtN(totGastos), true)}<div style='display:flex;justify-content:space-between;align-items:baseline;padding:9px 0 0;margin-top:6px;border-top:1px solid rgba(255,255,255,.22)'><span style='font-size:11px;font-weight:700;color:#fff'>${T.availBalance}</span><span style='font-size:15px;font-weight:700;color:#fff;white-space:nowrap'>${saldo<0?'−':''}${fmtN(saldo)}</span></div></div>`
  // Cabecera ejecutiva (diseño A): 3 cifras clave arriba — Fondos · Gastos del período · Saldo (destacado).
  const saldoPos = saldo>=0
  const kpiCard = (l,v,bg,fg)=>`<div style='background:${bg};padding:12px 16px;flex:1'><div style='font-size:8px;font-weight:600;color:${fg==='#fff'?'rgba(255,255,255,.7)':AZUL3};text-transform:uppercase;letter-spacing:.4px'>${l}</div><div style='font-size:17px;font-weight:700;color:${fg};margin-top:2px;white-space:nowrap'>${v}</div></div>`
  const kpiRow = `<div style='display:flex;gap:1px;background:${GRAY}'>${kpiCard(T.fundsReceived,fmtN(totFondos),'#fff','#0F6E56')}${kpiCard(T.expPeriod,fmtN(totGastos),'#fff',TXT)}${kpiCard(saldoPos?T.balFavor:T.balPending,(saldo<0?'−':'')+fmtN(Math.abs(saldo)),saldoPos?C.greenBg:C.overdueBg,saldoPos?C.greenText:C.overdueText)}</div>`
  const proyTxt = project ? `${project}${subproject?` · ${subproject}`:''}` : ''
  const proyBar = proyTxt ? `<div style='background:#fff;padding:7px 26px;border-bottom:1px solid ${GRAY};font-size:10px;color:${TXT}'><span style='color:${MUTED};font-weight:600;text-transform:uppercase;letter-spacing:.4px;font-size:9px'>${T.project}</span><span style='margin-left:10px;font-weight:600'>${proyTxt}</span></div>` : ''
  return `<!DOCTYPE html><html><head><meta charset='UTF-8'><title>${T.title} — ${razon}</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'DM Sans',Helvetica,Arial,sans-serif;color:${TXT};font-size:10px;background:#fff}.page{max-width:816px;margin:0 auto;padding-bottom:36px}@page{size:letter portrait;margin:14mm 14mm}table{width:100%;border-collapse:collapse;font-size:10px}thead th{padding:7px 10px;text-align:left;font-size:9px;font-weight:600;text-transform:uppercase;letter-spacing:.4px;color:${MUTED};border-bottom:1px solid ${GRAY}}tbody td{padding:7px 10px;border-bottom:1px solid #EFF1F3}.print-btn{position:fixed;bottom:20px;right:20px;background:${A};color:#fff;border:none;padding:10px 20px;border-radius:8px;font-size:12px;font-weight:600;cursor:pointer}@media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact}.no-print{display:none}.saldo-box{page-break-inside:avoid}tr{page-break-inside:avoid}}</style></head><body><div class='page'><div style='background:${A};padding:20px 26px;display:flex;justify-content:space-between;align-items:center'><img src='${logoBlanco}' alt='Liberona Escala Abogados' style='height:30px;display:block'/><div style='text-align:right'><div style='font-size:14px;font-weight:700;color:#fff'>${razon}</div>${rut?`<div style='font-size:11px;color:${AZUL3};margin-top:2px'>${rut}</div>`:''}</div></div><div style='background:${GRAY};padding:8px 26px;display:flex;justify-content:space-between;align-items:center;font-size:10px;color:${TXT}'><div style='display:flex;align-items:center'>${correlativo?`<span style='font-weight:700'>${T.reportNo} ${correlativo}</span>`:''}<span style='${correlativo?sep:"font-weight:700"}'>${T.issued}: ${fechaEmision}</span><span style='${sep}'>${T.expW(gastos.length)}</span></div>${dirigidoA?`<div style='font-weight:600'>${T.attn}: ${dirigidoA}</div>`:''}</div>${kpiRow}${proyBar}<div style='padding:20px 26px 0'><table><thead><tr><th>${T.date}</th><th>${T.concept}</th><th>${T.category}</th><th style='text-align:right'>${T.amount}</th></tr></thead><tbody>${filasGastos}</tbody></table><div style='display:flex;justify-content:space-between;padding:8px 10px;border-top:1.5px solid ${A};font-weight:700;font-size:11px'><span>${T.totalExp}</span><span>${fmtN(totGastos)}</span></div>${conRespaldoN>0?`<div style='font-size:9px;color:${MUTED};padding:3px 10px 0'>${T.withReceipt(conRespaldoN,gastos.length)}</div>`:''}<div style='font-size:10px;font-weight:700;color:${A};text-transform:uppercase;letter-spacing:.5px;margin:22px 0 8px'>${T.fundsSection}</div><table><tbody>${filasFondos}</tbody></table>${rendicionesPrevias.length?resumenBox:''}${saldoBox}</div><div style='display:flex;justify-content:space-between;padding:14px 26px 0;margin-top:22px;border-top:1px solid ${GRAY};font-size:9px;color:${MUTED}'><span>Av. Kennedy 7900, Of. 905, Vitacura · Santiago · leabogados.cl</span><span>${T.footerDoc}</span></div></div><button class='print-btn no-print' onclick='window.print()'>${T.printBtn}</button></body></html>`
}

