  'cl@leabogados.cl':{nombre:'Cristóbal Liberona',cargo:'Socio',telefono:'+56 9 9155 67 69'},
  'ee@leabogados.cl':{nombre:'Erasmo Escala',cargo:'Socio',telefono:'+56 9 6170 44 43'},
